// src/components/Leaderboard.js
import React, { useEffect, useState } from 'react';

const Leaderboard = () => {
  const [leaderboard, setLeaderboard] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetch('http://localhost:5001/api/leaderboard')
      .then((response) => {
        if (!response.ok) {
          throw new Error('Failed to fetch leaderboard data');
        }
        return response.json();
      })
      .then((data) => {
        setLeaderboard(data);
        setLoading(false);
      })
      .catch((err) => {
        console.error('Error fetching leaderboard:', err);
        setError(err.message);
        setLoading(false);
      });
  }, []);

  if (loading) {
    return (
      <div className="flex items-center justify-center h-screen">
        <p className="text-xl font-medium">Loading...</p>
      </div>
    );
  }

  if (error) {
    return (
      <div className="flex items-center justify-center h-screen">
        <p className="text-red-500 text-lg">{error}</p>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto my-10 px-4">
      <h1 className="text-3xl font-bold text-center mb-8">Codeforces Leaderboard</h1>
      <div className="overflow-x-auto">
        <table className="min-w-full bg-white shadow-md rounded-lg overflow-hidden">
          <thead className="bg-gray-200">
            <tr>
              <th className="py-3 px-5 text-left">Username</th>
              <th className="py-3 px-5 text-left">Rating</th>
              <th className="py-3 px-5 text-left">Max Rating</th>
              <th className="py-3 px-5 text-left">Rank</th>
              <th className="py-3 px-5 text-left">Max Rank</th>
            </tr>
          </thead>
          <tbody>
            {leaderboard.map((user, index) => (
              <tr key={index} className="border-t hover:bg-gray-100">
                <td className="py-3 px-5">{user.username}</td>
                <td className="py-3 px-5">{user.rating || 'N/A'}</td>
                <td className="py-3 px-5">{user.maxRating || 'N/A'}</td>
                <td className="py-3 px-5 capitalize">{user.rank}</td>
                <td className="py-3 px-5 capitalize">{user.maxRank}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default Leaderboard;
